// Normaliza el body del webhook y rutea por acción.
const body = ($input.first().json.body) || $input.first().json || {};
const action = body.action || 'getThread';
return [{ json: { action, thread_id: body.thread_id || '', to: body.to || '', subject: body.subject || '', text: body.body || body.text || '', gmail_action: body.gmail_action || body.action } }];

// Parsea la respuesta de la Gmail API a {asunto, participantes, mensajes:[{from,to,subject,date,body,snippet}]}.
const me = 'blas.rivera@uflouniversidad.edu.ar';
const t = $input.first().json;
function header(headers, name) {
  const h = (headers || []).find(x => (x.name || '').toLowerCase() === name.toLowerCase());
  return h ? h.value : '';
}
function decodeB64(data) {
  if (!data) return '';
  try { return Buffer.from(data.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf-8'); } catch (e) { return ''; }
}
function extractBody(payload) {
  if (!payload) return '';
  if (payload.mimeType === 'text/plain' && payload.body && payload.body.data) return decodeB64(payload.body.data);
  if (payload.parts) {
    // preferir text/plain
    const plain = payload.parts.find(p => p.mimeType === 'text/plain');
    if (plain && plain.body && plain.body.data) return decodeB64(plain.body.data);
    for (const p of payload.parts) { const b = extractBody(p); if (b) return b; }
  }
  if (payload.body && payload.body.data) return decodeB64(payload.body.data);
  return '';
}
const msgs = (t.messages || []).map(m => {
  const h = (m.payload && m.payload.headers) || [];
  const from = header(h, 'From');
  return {
    id: m.id,
    from,
    to: header(h, 'To'),
    subject: header(h, 'Subject'),
    date: header(h, 'Date'),
    body: extractBody(m.payload),
    snippet: m.snippet || '',
    from_me: from.toLowerCase().includes(me)
  };
});
const asunto = msgs.length ? msgs[0].subject.replace(/^(Re:|Fwd:|RE:|FW:)\s*/i, '') : '';
const participantes = Array.from(new Set(msgs.flatMap(m => [m.from, m.to]).join(',').split(',').map(s => { const mm = s.match(/<([^>]+)>/); return (mm ? mm[1] : s).trim(); }).filter(Boolean)));
return [{ json: { thread_id: t.id, asunto, participantes, mensajes: msgs } }];

// Construye el mensaje MIME (RFC822) y lo codifica en base64url para la Gmail API.
const d = $('Prep input').first().json;
const to = d.to;
let subject = d.subject || '';
if (!/^re:/i.test(subject)) subject = 'Re: ' + subject;
const body = d.text || '';
const mime = [
  `To: ${to}`,
  `Subject: ${subject}`,
  'Content-Type: text/plain; charset="UTF-8"',
  'MIME-Version: 1.0',
  '',
  body
].join('\r\n');
const raw = Buffer.from(mime, 'utf-8').toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
return [{ json: { raw, threadId: d.thread_id } }];

// Mapea la acción de modificación a labels add/remove y arma la URL.
const d = $('Prep input').first().json;
const action = d.gmail_action || d.action;
const threadId = d.thread_id;
let addLabelIds = [];
let removeLabelIds = [];
let trash = false;
if (action === 'archive') removeLabelIds = ['INBOX'];
else if (action === 'markRead') removeLabelIds = ['UNREAD'];
else if (action === 'markUnread') addLabelIds = ['UNREAD'];
else if (action === 'trash') trash = true;
const url = trash
  ? `https://gmail.googleapis.com/gmail/v1/users/me/threads/${threadId}/trash`
  : `https://gmail.googleapis.com/gmail/v1/users/me/threads/${threadId}/modify`;
return [{ json: { url, trash, body: trash ? {} : { addLabelIds, removeLabelIds } } }];
